A debounce function delays the execution of a function until a certain amount of time has passed without it being called again.

```javascript
function debounce(func, delay) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(context, args), delay);
  };
}

// Example Usage:

function search(query) {
  console.log("Searching for:", query);
}

// Create a debounced version of the search function with a 500ms delay
const debouncedSearch = debounce(search, 500);

// Simulate rapid typing
debouncedSearch("apple");
debouncedSearch("appl");
debouncedSearch("app");
debouncedSearch("appl");
debouncedSearch("apple"); // Only this one will trigger after 500ms of no further calls

// After 500ms, "Searching for: apple" will be logged once.
```
